146→const UNIT_QUEUE_SIZE = { width: 241, height: 93 } as const;
147→const UNIT_QUEUE_ACTIVE_ICON_BOX = { x: 6, y: 5, width: 42, height: 42 } as const;
148→const UNIT_QUEUE_ICON_BOXES = [
149→  UNIT_QUEUE_ACTIVE_ICON_BOX,
150→  { x: 5, y: 57, width: 31, height: 30 },
151→  { x: 45, y: 58, width: 31, height: 30 },
152→  { x: 85, y: 58, width: 31, height: 30 },
153→  { x: 125, y: 58, width: 31, height: 30 },
154→] as const;
