439→  private renderTooltips(vpRect: DOMRect) {
440→    const { ctx, batcher, blend, raceTex } = this;
441→    const gl = ctx.gl;
442→
443→    for (const tt of this.tooltips) {
444→      const el = tt.ref();
445→      if (!el) continue;
446→      const rect = el.getBoundingClientRect();
447→      if (!this.isVisible(rect, vpRect)) continue;
448→
449→      batcher.flush();
450→      blend.useProgram(ctx.tiledProg);
451→      gl.uniform2f(ctx.tiledLocs.resolution, ctx.canvasW * ctx.dpr, ctx.canvasH * ctx.dpr);
452→      gl.uniform1i(ctx.tiledLocs.tex, 0);
453→      gl.uniform2f(ctx.tiledLocs.quadSize, rect.width, rect.height);
454→      gl.uniform2f(ctx.tiledLocs.tileSize, 64, 64);
455→      gl.uniform1i(ctx.tiledLocs.alphaMode, 0);
456→      batcher.batchTex = null;
457→      blend.setBlend('BLEND');
458→      batcher.drawQuad(rect.left, rect.top, rect.width, rect.height, raceTex.tooltipBgTiled, 0, 0, 1, 1);
459→      batcher.flush();
460→
461→      blend.useProgram(ctx.quadProg);
462→      gl.uniform2f(ctx.quadLocs.resolution, ctx.canvasW * ctx.dpr, ctx.canvasH * ctx.dpr);
463→      gl.uniform1i(ctx.quadLocs.tex, 0);
464→      gl.uniform1i(ctx.quadLocs.alphaMode, 0);
465→      batcher.batchTex = null;
466→
467→      const bw = 2;
468→      const br = 0.784, bg = 0.659, bb = 0.306;
469→      batcher.drawQuad(rect.left, rect.top, rect.width, bw, null, 0,0,1,1, br, bg, bb, 1);
470→      batcher.drawQuad(rect.left, rect.bottom - bw, rect.width, bw, null, 0,0,1,1, br, bg, bb, 1);
471→      batcher.drawQuad(rect.left, rect.top, bw, rect.height, null, 0,0,1,1, br, bg, bb, 1);
472→      batcher.drawQuad(rect.right - bw, rect.top, bw, rect.height, null, 0,0,1,1, br, bg, bb, 1);
473→    }
474→  }
